ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?project_name ?name WHERE {
  ?supplies a :Supplies .
  ?projects a :Projects .
  ?projects p:hasSupplies ?supplies .
  ?projects p:project_name ?project_name .
  ?supplies p:name ?name .
} }
  full: { SELECT ?project_name ?title ?name WHERE {
  ?textbooks a :Textbooks .
  ?projects a :Projects .
  ?projects p:hasTextbooks ?textbooks .
  ?supplies a :Supplies .
  ?projects p:hasSupplies ?supplies .
  ?projects p:project_name ?project_name .
  ?textbooks p:title ?title .
  ?supplies p:name ?name .
} }
  component_2: { SELECT ?project_name ?title WHERE {
  ?textbooks a :Textbooks .
  ?projects a :Projects .
  ?projects p:hasTextbooks ?textbooks .
  ?projects p:project_name ?project_name .
  ?textbooks p:title ?title .
} }
}

PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?title WHERE {
  ?textbooks a :Textbooks .
  ?projects a :Projects .
  ?projects p:hasTextbooks ?textbooks .
  ?textbooks p:title ?title .
  ?projects p:project_name ?project_name_f .
  FILTER(STR(?project_name_f) = "Optical Spectroscopy")
} }
  full: { SELECT ?title ?name WHERE {
  ?textbooks a :Textbooks .
  ?projects a :Projects .
  ?projects p:hasTextbooks ?textbooks .
  ?supplies a :Supplies .
  ?projects p:hasSupplies ?supplies .
  ?textbooks p:title ?title .
  ?supplies p:name ?name .
  ?projects p:project_name ?project_name_f .
  FILTER(STR(?project_name_f) = "Optical Spectroscopy")
} }
  component_2: { SELECT ?name WHERE {
  ?supplies a :Supplies .
  ?projects a :Projects .
  ?projects p:hasSupplies ?supplies .
  ?supplies p:name ?name .
  ?projects p:project_name ?project_name_f .
  FILTER(STR(?project_name_f) = "Optical Spectroscopy")
} }
}
